mapper.select:
SELECT a.dept_id "deptId", DATE_FORMAT(a.contract_time, '%Y-%m') AS "contractTime", ROUND(SUM(a.total_amount) / 1000000, 2) "sumTotalAmount" FROM t_ctr_contract a WHERE a.business_type = 'ZY-BB' and a.contract_status !='C' and a.contract_type = 'S'
and DATE_FORMAT(a.contract_time, '%Y-%m') >=#{monthBegin}
and DATE_FORMAT(a.contract_time, '%Y-%m') <=#{monthEnd}
and a.dept_id in
#{item}
group by a.dept_id,contractTime order by a.dept_id desc,contractTime asc
